"""
Python implementation of YANG-like data modeling for IoT devices
Demonstrates core YANG constructs: leaf, container, list with validation
"""
from dataclasses import dataclass, field
from typing import Any, List, Optional, Union
from datetime import datetime
import re

# YANG Data Types (simplified implementation)
class YANGType:
    """Base class for YANG types"""
    def __init__(self, name: str):
        self.name = name

    def validate(self, value: Any) -> bool:
        raise NotImplementedError

class StringType(YANGType):
    def __init__(self, pattern: str = None):
        super().__init__("string")
        self.pattern = pattern

    def validate(self, value: Any) -> bool:
        if not isinstance(value, str):
            return False
        if self.pattern and not re.match(self.pattern, value):
            return False
        return True

class UInt32Type(YANGType):
    def __init__(self, range_min: int = 0, range_max: int = 4294967295):
        super().__init__("uint32")
        self.range = (range_min, range_max)

    def validate(self, value: Any) -> bool:
        if not isinstance(value, int) or value < 0:
            return False
        return self.range[0] <= value <= self.range[1]

class Decimal64Type(YANGType):
    def __init__(self, fraction_digits: int = 2):
        super().__init__("decimal64")
        self.fraction_digits = fraction_digits

    def validate(self, value: Any) -> bool:
        # Simplified: check if numeric
        try:
            float(value)
            return True
        except (ValueError, TypeError):
            return False

class BooleanType(YANGType):
    def __init__(self):
        super().__init__("boolean")

    def validate(self, value: Any) -> bool:
        return isinstance(value, bool)

# YANG Leaf definition
@dataclass
class YANGLeaf:
    """Represents a YANG leaf (single value)"""
    name: str
    yang_type: YANGType
    description: str = ""
    default_value: Any = None
    mandatory: bool = False
    units: str = ""

    def validate(self, value: Any) -> tuple:
        """Validate leaf value, return (success, error_message)"""
        if value is None:
            if self.mandatory:
                return False, f"{self.name}: mandatory leaf missing"
            if self.default_value is not None:
                return True, "used default"
            return True, "no value"

        if not self.yang_type.validate(value):
            return False, f"{self.name}: invalid type {type(value).__name__} for {self.yang_type.name}"
        return True, "valid"

# YANG Container definition
class YANGContainer:
    """Represents a YANG container (hierarchy of nodes)"""
    def __init__(self, name: str, config: bool = True):
        self.name = name
        self.config = config  # True = configuration, False = state data
        self.children: List[Union[YANGLeaf, 'YANGContainer', 'YANGList']] = []

    def add_child(self, child):
        self.children.append(child)

    def validate(self, data: dict) -> List[str]:
        """Validate data against container schema"""
        errors = []
        for child in self.children:
            if isinstance(child, YANGLeaf):
                value = data.get(child.name)
                valid, msg = child.validate(value)
                if not valid and msg != "used default" and msg != "no value":
                    errors.append(msg)
        return errors

# YANG List definition
class YANGList:
    """Represents a YANG list (sequence of entries)"""
    def __init__(self, name: str, key_leaf: str):
        self.name = name
        self.key_leaf = key_leaf
        self.entries: List[YANGContainer] = []

    def add_entry(self, entry: YANGContainer):
        self.entries.append(entry)

    def validate(self, data: List[dict]) -> List[str]:
        """Validate list data"""
        errors = []
        # Check for duplicate keys
        keys = [entry.get(self.key_leaf) for entry in data]
        if len(keys) != len(set(keys)):
            errors.append(f"{self.name}: duplicate key '{self.key_leaf}'")
        return errors

# Build IoT Sensor YANG Model
def create_iot_sensor_model():
    """Create YANG model for IoT temperature sensor"""

    # Module definition (conceptual)
    module = {
        "name": "iot-temperature-sensor",
        "namespace": "http://example.com/iot-sensor",
        "prefix": "iot-temp"
    }

    # Container: device-config (config true - writable)
    device_config = YANGContainer("device-config", config=True)
    device_config.add_child(YANGLeaf(
        "device-id",
        StringType(),
        description="Unique device identifier",
        mandatory=True
    ))
    device_config.add_child(YANGLeaf(
        "sampling-interval",
        UInt32Type(range_min=1, range_max=3600),
        description="Interval between sensor readings",
        default_value=60,
        units="seconds"
    ))
    device_config.add_child(YANGLeaf(
        "enabled",
        BooleanType(),
        description="Device enable status",
        default_value=True
    ))

    # Container: sensor-state (config false - read-only)
    sensor_state = YANGContainer("sensor-state", config=False)
    sensor_state.add_child(YANGLeaf(
        "temperature",
        Decimal64Type(fraction_digits=2),
        description="Current temperature reading",
        units="celsius"
    ))
    sensor_state.add_child(YANGLeaf(
        "battery-level",
        UInt32Type(range_min=0, range_max=100),
        description="Battery percentage",
        units="percent"
    ))
    sensor_state.add_child(YANGLeaf(
        "last-updated",
        StringType(),
        description="Timestamp of last reading"
    ))

    return {"module": module, "device-config": device_config, "sensor-state": sensor_state}

# Test the YANG model
if __name__ == "__main__":
    # Create model
    model = create_iot_sensor_model()

    # Test valid configuration
    print("=== Testing Valid Configuration ===")
    config_data = {
        "device-id": "sensor-001",
        "sampling-interval": 30,
        "enabled": True
    }
    errors = model["device-config"].validate(config_data)
    if errors:
        print(f"Errors: {errors}")
    else:
        print(f"Valid config: {config_data}")

    # Test invalid configuration
    print("\n=== Testing Invalid Configuration ===")
    invalid_config = {
        "device-id": "sensor-001",
        "sampling-interval": 5000,  # Exceeds max
        "enabled": True
    }
    errors = model["device-config"].validate(invalid_config)
    if errors:
        print(f"Validation errors: {errors}")

    # Test missing mandatory field
    print("\n=== Testing Missing Mandatory Field ===")
    missing_config = {
        "enabled": True
    }
    errors = model["device-config"].validate(missing_config)
    if errors:
        print(f"Validation errors: {errors}")

    # Test state data (read-only)
    print("\n=== Testing State Data ===")
    state_data = {
        "temperature": 23.5,
        "battery-level": 85,
        "last-updated": "2024-01-15T10:30:00Z"
    }
    errors = model["sensor-state"].validate(state_data)
    if errors:
        print(f"Errors: {errors}")
    else:
        print(f"Valid state: {state_data}")

/*
 * C Implementation: YANG-like Data Structures for IoT Device Management
 * Demonstrates core YANG constructs using C data structures
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>
#include <stdint.h>

/* YANG Type Enumeration */
typedef enum {
    YANG_STRING,
    YANG_UINT32,
    YANG_INT32,
    YANG_DECIMAL64,
    YANG_BOOLEAN,
    YANG_DATE_AND_TIME
} YANGTypeEnum;

/* YANG Leaf Structure */
typedef struct {
    char name[64];
    YANGTypeEnum type;
    bool is_mandatory;
    bool is_config;  // true = configuration, false = state
    char units[32];
    void *default_value;
    char description[256];
} YANGLeaf;

/* YANG Container Structure */
typedef struct {
    char name[64];
    bool is_config;
    YANGLeaf *leaves;
    int leaf_count;
    char description[256];
} YANGContainer;

/* YANG List Entry Structure */
typedef struct {
    char key_value[64];  // Key for this entry
    YANGContainer data;
} YANGListEntry;

/* YANG List Structure */
typedef struct {
    char name[64];
    char key_name[64];
    YANGListEntry *entries;
    int entry_count;
} YANGList;

/* IoT Device Configuration Structure */
typedef struct {
    char device_id[64];
    uint32_t sampling_interval;  // in seconds
    bool enabled;
    char description[256];
} IoTDeviceConfig;

/* IoT Sensor State Structure */
typedef struct {
    double temperature;        // in Celsius
    double humidity;           // in percentage
    uint8_t battery_level;     // 0-100%
    char last_updated[32];     // timestamp
} SensorState;

/* Complete IoT Sensor YANG Model */
typedef struct {
    YANGContainer device_config;
    YANGContainer sensor_state;
    YANGList reading_history;
} IOTSensorModel;

/* Function to initialize YANG container */
void init_yang_container(YANGContainer *container, const char *name, 
                         bool is_config, const char *desc) {
    strncpy(container->name, name, 63);
    container->name[63] = '\0';
    container->is_config = is_config;
    strncpy(container->description, desc, 255);
    container->description[255] = '\0';
    container->leaf_count = 0;
    container->leaves = NULL;
}

/* Function to add leaf to container */
void container_add_leaf(YANGContainer *container, const char *name,
                        YANGTypeEnum type, bool mandatory, bool is_config,
                        const char *units, const char *desc) {
    container->leaves = realloc(container->leaves, 
                                 (container->leaf_count + 1) * sizeof(YANGLeaf));

    YANGLeaf *leaf = &container->leaves[container->leaf_count];
    strncpy(leaf->name, name, 63);
    leaf->name[63] = '\0';
    leaf->type = type;
    leaf->is_mandatory = mandatory;
    leaf->is_config = is_config;
    strncpy(leaf->units, units, 31);
    leaf->units[31] = '\0';
    strncpy(leaf->description, desc, 255);
    leaf->description[255] = '\0';

    container->leaf_count++;
}

/* Validation function for YANG types */
bool validate_leaf_value(YANGLeaf *leaf, void *value) {
    if (value == NULL) {
        return !leaf->is_mandatory;  // Mandatory must have value
    }

    switch (leaf->type) {
        case YANG_UINT32: {
            uint32_t *val = (uint32_t *)value;
            // Example: sampling interval 1-3600 seconds
            if (strcmp(leaf->name, "sampling-interval") == 0) {
                return (*val >= 1 && *val <= 3600);
            }
            return true;
        }
        case YANG_BOOLEAN:
            return true;  // Boolean always valid
        case YANG_DECIMAL64:
            return true;  // Simplified validation
        case YANG_STRING:
            return true;
        default:
            return true;
    }
}

/* Function to validate device configuration */
int validate_device_config(IoTDeviceConfig *config) {
    int errors = 0;

    // Validate device-id (mandatory string)
    if (config->device_id[0] == '\0') {
        printf("Error: device-id is mandatory\n");
        errors++;
    }

    // Validate sampling interval
    if (config->sampling_interval < 1 || config->sampling_interval > 3600) {
        printf("Error: sampling-interval must be 1-3600 seconds\n");
        errors++;
    }

    return errors;
}

/* Function to print device configuration (NETCONF-like XML output) */
void print_config_xml(IoTDeviceConfig *config) {
    printf("<!-- NETCONF get-config reply -->\n");
    printf("<rpc-reply message-id=\"101\" xmlns=\"urn:ietf:params:xml:ns:netconf:base:1.0\">\n");
    printf("  <data>\n");
    printf("    <device-config xmlns=\"http://example.com/iot-sensor\">\n");
    printf("      <device-id>%s</device-id>\n", config->device_id);
    printf("      <sampling-interval>%u</sampling-interval>\n", 
           config->sampling_interval);
    printf("      <enabled>%s</enabled>\n", 
           config->enabled ? "true" : "false");
    printf("    </device-config>\n");
    printf("  </data>\n");
    printf("</rpc-reply>\n");
}

/* Function to print sensor state */
void print_state_xml(SensorState *state) {
    printf("<!-- NETCONF get reply (state data) -->\n");
    printf("<rpc-reply message-id=\"102\" xmlns=\"urn:ietf:params:xml:ns:netconf:base:1.0\">\n");
    printf("  <data>\n");
    printf("    <sensor-state xmlns=\"http://example.com/iot-sensor\" config=\"false\">\n");
    printf("      <temperature>%.2f</temperature>\n", state->temperature);
    printf("      <humidity>%.2f</humidity>\n", state->humidity);
    printf("      <battery-level>%u</battery-level>\n", state->battery_level);
    printf("      <last-updated>%s</last-updated>\n", state->last_updated);
    printf("    </sensor-state>\n");
    printf("  </data>\n");
    printf("</rpc-reply>\n");
}

/* Simulate NETCONF edit-config operation */
int netconf_edit_config(IoTDeviceConfig *current_config, 
                        const char *device_id, 
                        uint32_t sampling_interval,
                        bool enabled) {
    printf("\n=== NETCONF edit-config Operation ===\n");

    // Validate before applying
    IoTDeviceConfig new_config;
    strncpy(new_config.device_id, device_id, 63);
    new_config.sampling_interval = sampling_interval;
    new_config.enabled = enabled;

    int errors = validate_device_config(&new_config);
    if (errors > 0) {
        printf("Edit-config failed with %d errors\n", errors);
        return -1;
    }

    // Apply changes (atomic operation)
    memcpy(current_config, &new_config, sizeof(IoTDeviceConfig));

    printf("Configuration applied successfully\n");
    return 0;
}

int main() {
    printf("=== YANG Data Model Demo for IoT Devices ===\n\n");

    // Initialize device configuration
    IoTDeviceConfig sensor_config = {
        .device_id = "sensor-001",
        .sampling_interval = 60,
        .enabled = true
    };

    // Initialize sensor state (read-only)
    SensorState sensor_state = {
        .temperature = 23.50,
        .humidity = 65.20,
        .battery_level = 85,
        .last_updated = "2024-01-15T10:30:00Z"
    };

    // Display current configuration (NETCONF format)
    printf("--- Current Configuration ---\n");
    print_config_xml(&sensor_config);

    // Display current state
    printf("\n--- Current State ---\n");
    print_state_xml(&sensor_state);

    // Demonstrate NETCONF edit-config
    int result = netconf_edit_config(&sensor_config, "sensor-001", 30, true);

    if (result == 0) {
        printf("\n--- Updated Configuration ---\n");
        print_config_xml(&sensor_config);
    }

    // Demonstrate validation errors
    printf("\n=== Testing Invalid Configuration ===\n");
    netconf_edit_config(&sensor_config, "sensor-001", 5000, true);  // Invalid interval

    return 0;
}
